    ('Antalya', 'Dürüm', 'https://images.openfoodfacts.org/images/products/541/251/493/5429/front_de.29.400.jpg', 'off_api', 'front', true, 'Front — EAN 5412514935429', 'front_5412514935429'),
    ('Lieken Urkorn', 'Kleines Kerni', 'https://images.openfoodfacts.org/images/products/400/924/902/0240/front_de.56.400.jpg', 'off_api', 'front', true, 'Front — EAN 4009249020240', 'front_4009249020240'),
    ('Goldähren', 'Toast Brötchen', 'https://images.openfoodfacts.org/images/products/000/002/904/8465/front_en.32.400.jpg', 'off_api', 'front', true, 'Front — EAN 29048465', 'front_29048465'),
    ('Harry', 'Vital+ Dinkel Vollkorn 100% Dinkel & mit Sonnenblumenkernen 4071800054469 Dinkelvollkornbrot mit 55 % Dinkelvollkornanteil', 'https://images.openfoodfacts.org/images/products/407/180/005/4469/front_de.32.400.jpg', 'off_api', 'front', true, 'Front — EAN 4071800054469', 'front_4071800054469'),
    ('REWE Bio', 'Mehrkorn Landbrötchen 4337256534147', 'https://images.openfoodfacts.org/images/products/433/725/653/4147/front_de.32.400.jpg', 'off_api', 'front', true, 'Front — EAN 4337256534147', 'front_4337256534147'),
    ('Alnatura', 'Alnatura Hafer & Saaten ohne Mehl und Hefe 40045139', 'https://images.openfoodfacts.org/images/products/000/004/004/5139/front_en.20.400.jpg', 'off_api', 'front', true, 'Front — EAN 40045139', 'front_40045139'),
    ('Lieken Urkorn', 'Lieken Urkorn Lieblingsbrot Dinkel Roggen', 'https://images.openfoodfacts.org/images/products/400/924/905/0070/front_de.11.400.jpg', 'off_api', 'front', true, 'Front — EAN 4009249050070', 'front_4009249050070')
) AS d(brand, product_name, url, source, image_type, is_primary, alt_text, off_image_id)
JOIN products p ON p.country = 'DE' AND p.brand = d.brand AND p.product_name = d.product_name
  AND p.category = 'Bread' AND p.is_deprecated IS NOT TRUE
ON CONFLICT (off_image_id) WHERE off_image_id IS NOT NULL DO UPDATE SET
  url = EXCLUDED.url,
  image_type = EXCLUDED.image_type,
  is_primary = EXCLUDED.is_primary,
  alt_text = EXCLUDED.alt_text;
